    return try FfiConverterTypeVoiceLoader.lift(pointer)
}

public func FfiConverterTypeVoiceLoader_lower(_ value: VoiceLoader) -> UnsafeMutableRawPointer {
    return FfiConverterTypeVoiceLoader.lower(value)
}


